24	void (*ref_difftest_memcpy)(paddr_t addr, void *buf, size_t n, bool direction) = NULL;
25	void (*ref_difftest_regcpy)(void *dut, bool direction) = NULL;
26	void (*ref_difftest_exec)(uint64_t n) = NULL;
