29	#ifdef CONFIG_DIFFTEST
30	
31	static bool is_skip_ref = false;
32	static int skip_dut_nr_inst = 0;
33	
34	// this is used to let ref skip instructions which
35	// can not produce consistent behavior with NEMU
36	void difftest_skip_ref() {
37	  is_skip_ref = true;
38	  // If such an instruction is one of the instruction packing in QEMU
39	  // (see below), we end the process of catching up with QEMU's pc to
40	  // keep the consistent behavior in our best.
41	  // Note that this is still not perfect: if the packed instructions
42	  // already write some memory, and the incoming instruction in NEMU
43	  // will load that memory, we will encounter false negative. But such
44	  // situation is infrequent.
45	  skip_dut_nr_inst = 0;
46	}
47	
48	// this is used to deal with instruction packing in QEMU.
49	// Sometimes letting QEMU step once will execute multiple instructions.
50	// We should skip checking until NEMU's pc catches up with QEMU's pc.
51	// The semantic is
52	//   Let REF run `nr_ref` instructions first.
53	//   We expect that DUT will catch up with REF within `nr_dut` instructions.
54	void difftest_skip_dut(int nr_ref, int nr_dut) {
55	  skip_dut_nr_inst += nr_dut;
56	
57	  while (nr_ref -- > 0) {
58	    ref_difftest_exec(1);
59	  }
60	}
61	
62	void init_difftest(char *ref_so_file, long img_size, int port) {
63	  assert(ref_so_file != NULL);
64	
65	  void *handle;
66	  handle = dlopen(ref_so_file, RTLD_LAZY);
67	  assert(handle);
68	
69	  ref_difftest_memcpy = dlsym(handle, "difftest_memcpy");
70	  assert(ref_difftest_memcpy);
71	
72	  ref_difftest_regcpy = dlsym(handle, "difftest_regcpy");
73	  assert(ref_difftest_regcpy);
74	
75	  ref_difftest_exec = dlsym(handle, "difftest_exec");
76	  assert(ref_difftest_exec);
77	
78	  ref_difftest_raise_intr = dlsym(handle, "difftest_raise_intr");
79	  assert(ref_difftest_raise_intr);
80	
81	  void (*ref_difftest_init)(int) = dlsym(handle, "difftest_init");
82	  assert(ref_difftest_init);
83	
84	  Log("Differential testing: %s", ANSI_FMT("ON", ANSI_FG_GREEN));
85	  Log("The result of every instruction will be compared with %s. "
86	      "This will help you a lot for debugging, but also significantly reduce the performance. "
87	      "If it is not necessary, you can turn it off in menuconfig.", ref_so_file);
88	
89	  ref_difftest_init(port);
90	  ref_difftest_memcpy(RESET_VECTOR, guest_to_host(RESET_VECTOR), img_size, DIFFTEST_TO_REF);
91	  ref_difftest_regcpy(&cpu, DIFFTEST_TO_REF);
92	}
93	
94	static void checkregs(CPU_state *ref, vaddr_t pc) {
95	  if (!isa_difftest_checkregs(ref, pc)) {
96	    nemu_state.state = NEMU_ABORT;
97	    nemu_state.halt_pc = pc;
98	    isa_reg_display();
99	  }
100	}
101	
102	void difftest_step(vaddr_t pc, vaddr_t npc) {
103	  CPU_state ref_r;
104	
105	  if (skip_dut_nr_inst > 0) {
106	    ref_difftest_regcpy(&ref_r, DIFFTEST_TO_DUT);
107	    if (ref_r.pc == npc) {
108	      skip_dut_nr_inst = 0;
109	      checkregs(&ref_r, npc);
110	      return;
111	    }
112	    skip_dut_nr_inst --;
113	    if (skip_dut_nr_inst == 0)
114	      panic("can not catch up with ref.pc = " FMT_WORD " at pc = " FMT_WORD, ref_r.pc, pc);
115	    return;
116	  }
117	
118	  if (is_skip_ref) {
119	    // to skip the checking of an instruction, just copy the reg state to reference design
120	    ref_difftest_regcpy(&cpu, DIFFTEST_TO_REF);
121	    is_skip_ref = false;
122	    return;
123	  }
124	
125	  ref_difftest_exec(1);
126	  ref_difftest_regcpy(&ref_r, DIFFTEST_TO_DUT);
127	
128	  checkregs(&ref_r, pc);
129	}
