26	
27	static void welcome() {
28	  Log("Trace: %s", MUXDEF(CONFIG_TRACE, ANSI_FMT("ON", ANSI_FG_GREEN), ANSI_FMT("OFF", ANSI_FG_RED)));
29	  IFDEF(CONFIG_TRACE, Log("If trace is enabled, a log file will be generated "
30	        "to record the trace. This may lead to a large log file. "
31	        "If it is not necessary, you can disable it in menuconfig"));
32	  Log("Build time: %s, %s", __TIME__, __DATE__);
33	  printf("Welcome to %s-NEMU!\n", ANSI_FMT(str(__GUEST_ISA__), ANSI_FG_YELLOW ANSI_BG_RED));
34	  printf("For help, type \"help\"\n");
35	  Log("Exercise: Please remove me in the source code and compile NEMU again.");
36	  assert(0);
37	}
