39	#ifndef CONFIG_TARGET_AM
40	#include <getopt.h>
41	
42	void sdb_set_batch_mode();
43	
44	static char *log_file = NULL;
45	static char *diff_so_file = NULL;
46	static char *img_file = NULL;
47	static int difftest_port = 1234;
48	
49	static long load_img() {
50	  if (img_file == NULL) {
51	    Log("No image is given. Use the default build-in image.");
52	    return 4096; // built-in image size
53	  }
54	
55	  FILE *fp = fopen(img_file, "rb");
56	  Assert(fp, "Can not open '%s'", img_file);
57	
58	  fseek(fp, 0, SEEK_END);
59	  long size = ftell(fp);
60	
61	  Log("The image is %s, size = %ld", img_file, size);
62	
63	  fseek(fp, 0, SEEK_SET);
64	  int ret = fread(guest_to_host(RESET_VECTOR), size, 1, fp);
65	  assert(ret == 1);
66	
67	  fclose(fp);
68	  return size;
69	}
70	
71	static int parse_args(int argc, char *argv[]) {
72	  const struct option table[] = {
73	    {"batch"    , no_argument      , NULL, 'b'},
74	    {"log"      , required_argument, NULL, 'l'},
75	    {"diff"     , required_argument, NULL, 'd'},
76	    {"port"     , required_argument, NULL, 'p'},
77	    {"help"     , no_argument      , NULL, 'h'},
78	    {0          , 0                , NULL,  0 },
79	  };
80	  int o;
81	  while ( (o = getopt_long(argc, argv, "-bhl:d:p:", table, NULL)) != -1) {
82	    switch (o) {
83	      case 'b': sdb_set_batch_mode(); break;
84	      case 'p': sscanf(optarg, "%d", &difftest_port); break;
85	      case 'l': log_file = optarg; break;
86	      case 'd': diff_so_file = optarg; break;
87	      case 1: img_file = optarg; return 0;
88	      default:
89	        printf("Usage: %s [OPTION...] IMAGE [args]\n\n", argv[0]);
90	        printf("\t-b,--batch              run with batch mode\n");
91	        printf("\t-l,--log=FILE           output log to FILE\n");
92	        printf("\t-d,--diff=REF_SO        run DiffTest with reference REF_SO\n");
93	        printf("\t-p,--port=PORT          run DiffTest with port PORT\n");
94	        printf("\n");
95	        exit(0);
96	    }
97	  }
98	  return 0;
99	}
100	
101	void init_monitor(int argc, char *argv[]) {
102	  /* Perform some global initialization. */
103	
104	  /* Parse arguments. */
105	  parse_args(argc, argv);
106	
107	  /* Set random seed. */
108	  init_rand();
109	
110	  /* Open the log file. */
111	  init_log(log_file);
112	
113	  /* Initialize memory. */
114	  init_mem();
115	
116	  /* Initialize devices. */
117	  IFDEF(CONFIG_DEVICE, init_device());
118	
119	  /* Perform ISA dependent initialization. */
120	  init_isa();
121	
122	  /* Load the image to memory. This will overwrite the built-in image. */
123	  long img_size = load_img();
124	
125	  /* Initialize differential testing. */
126	  init_difftest(diff_so_file, img_size, difftest_port);
127	
128	  /* Initialize the simple debugger. */
129	  init_sdb();
130	
131	  IFDEF(CONFIG_ITRACE, init_disasm());
132	
133	  /* Display welcome message. */
134	  welcome();
135	}
136	#else // CONFIG_TARGET_AM
137	static long load_img() {
138	  extern char bin_start, bin_end;
139	  size_t size = &bin_end - &bin_start;
140	  Log("img size = %ld", size);
141	  memcpy(guest_to_host(RESET_VECTOR), &bin_start, size);
142	  return size;
143	}
144	
145	void am_init_monitor() {
146	  init_rand();
147	  init_mem();
148	  init_isa();
149	  load_img();
150	  IFDEF(CONFIG_DEVICE, init_device());
151	  welcome();
152	}
153	#endif
